const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

canvas.width = window.innerWidth;
canvas.height = window.innerHeight;

let player = {
    x: canvas.width / 2,
    y: canvas.height / 2,
    speed: 5,
    lastFrameTime: null
};

function updatePlayerPosition(currentTime) {
    if (player.lastFrameTime === null) {
        player.lastFrameTime = currentTime;
        return;
    }

    const deltaTime = currentTime - player.lastFrameTime;
    player.x += player.speed * (deltaTime / 1000);
    player.y += player.speed * (deltaTime / 1000);

    player.lastFrameTime = currentTime;

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.fillStyle = 'blue';
    ctx.fillRect(player.x, player.y, 20, 20);
}

function gameLoop(currentTime) {
    updatePlayerPosition(currentTime);
    requestAnimationFrame(gameLoop);
}

requestAnimationFrame(gameLoop);